import scala.collection.mutable.ListBuffer

def solve(s: String, k: Long): String = {
  val result = ListBuffer[Char]()
  for (c <- s) {
    if (c.isLetter) {
      result += c
    } else if (c == '*') {
      if (result.nonEmpty) {
        result.remove(result.length - 1)
      }
    } else if (c == '#') {
      result ++= result
    } else if (c == '%') {
      result.reverse
    }
  }
  if (k < result.length) {
    result(k).toString
  } else {
    "."
  }
}
